import anthropic
import json

client = anthropic.Anthropic()

# --- tool implementations ---
def extract_entities(text: str) -> dict:
    r = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=256,
        system="Extract named entities. JSON: {\"people\":[],\"orgs\":[],\"places\":[]}",
        messages=[{"role":"user","content":text}]
    )
    return json.loads(r.content[0].text)

def classify_sentiment(text: str) -> str:
    r = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=8,
        system="One word: positive, negative, or neutral.",
        messages=[{"role":"user","content":text}]
    )
    return r.content[0].text.strip()

def generate_summary(text: str, context: str) -> str:
    r = client.messages.create(
        model="claude-opus-4-8", max_tokens=256,
        messages=[{"role":"user","content":f"Text: {text}\nContext: {context}\nSummarize."}]
    )
    return r.content[0].text

TOOL_REGISTRY = {
    "extract_entities": extract_entities,
    "classify_sentiment": classify_sentiment,
    "generate_summary": generate_summary,
}

TOOLS = [
    {"name":"extract_entities","description":"Extract named entities from text",
     "input_schema":{"type":"object","properties":{"text":{"type":"string"}},"required":["text"]}},
    {"name":"classify_sentiment","description":"Classify text sentiment",
     "input_schema":{"type":"object","properties":{"text":{"type":"string"}},"required":["text"]}},
    {"name":"generate_summary","description":"Generate a summary given text and context",
     "input_schema":{"type":"object","properties":{"text":{"type":"string"},"context":{"type":"string"}},"required":["text","context"]}},
]

# --- agent loop ---
def run_agent(user_input: str) -> str:
    messages = [{"role":"user","content":user_input}]
    while True:
        response = client.messages.create(
            model="claude-opus-4-8", max_tokens=1024, tools=TOOLS, messages=messages
        )
        if response.stop_reason == "end_turn":
            # LLM decided it is done
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""
        # execute every tool call in this response
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = TOOL_REGISTRY[block.name](**block.input)
                tool_results.append({
                    "type":"tool_result","tool_use_id":block.id,
                    "content":json.dumps(result)
                })
        messages.append({"role":"assistant","content":response.content})
        messages.append({"role":"user","content":tool_results})

print(run_agent("Analyze this document: 'Anthropic released Claude 4 in 2025, expanding its AI lineup.'"))

import anthropic, json

client = anthropic.Anthropic()

def extract_invoice_fields(invoice_text: str) -> dict:
    """Fixed workflow: always extract these exact four fields."""
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=(
            "Extract invoice fields. Return ONLY valid JSON with keys: "
            "vendor, amount_usd, date_iso, invoice_number. "
            "Use null for missing fields."
        ),
        messages=[{"role": "user", "content": invoice_text}]
    )
    return json.loads(response.content[0].text)

result = extract_invoice_fields(
    "Invoice #INV-2025-0042 from Acme Corp. Total: $1,234.56. Date: June 15, 2025."
)
print(result)
