TOOLS = [
    {"name":"web_search","description":"Search the web",
     "input_schema":{"type":"object","properties":{"query":{"type":"string"}},"required":["query"]}},
    {"name":"read_page","description":"Read a webpage",
     "input_schema":{"type":"object","properties":{"url":{"type":"string"}},"required":["url"]}},
]
TOOL_REGISTRY = {"web_search": web_search, "read_page": read_page}

def research_agent(question: str) -> str:
    messages = [{"role":"user","content":question}]
    for _ in range(10):  # hard step limit
        response = client.messages.create(
            model="claude-opus-4-8", max_tokens=1024,
            tools=TOOLS, messages=messages
        )
        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b,"text"))
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = TOOL_REGISTRY[block.name](**block.input)
                tool_results.append({"type":"tool_result","tool_use_id":block.id,"content":result})
        messages.append({"role":"assistant","content":response.content})
        messages.append({"role":"user","content":tool_results})
    return "Step limit reached."

print(research_agent("What are the key differences between transformer and LSTM architectures for NLP?"))

# BAD: agent loop for a task with fixed, known steps
def classify_email_agent(email: str) -> str:
    # Forces the LLM to choose steps every call — unnecessary for a one-step task
    return run_agent(f"Classify this email as spam or not-spam: {email}")

# GOOD: single LLM call with a fixed prompt
def classify_email(email: str) -> str:
    r = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=8,
        system="Reply with exactly one word: spam or not-spam.",
        messages=[{"role": "user", "content": email}]
    )
    return r.content[0].text.strip()

